   330→// ---------------------------------------------------------------------------
   331→// Internal helpers
   332→// ---------------------------------------------------------------------------
   333→
   334→function sortKeysDeep(value: unknown): unknown {
   335→  if (Array.isArray(value)) return value.map(sortKeysDeep)
   336→  if (value !== null && typeof value === 'object') {
   337→    const sorted: Record<string, unknown> = {}
   338→    for (const key of Object.keys(value as Record<string, unknown>).sort()) {
   339→      sorted[key] = sortKeysDeep((value as Record<string, unknown>)[key])
   340→    }
   341→    return sorted
   342→  }
   343→  return value
   344→}
   345→
   346→function formatUtcIso(d: Date): string {
   347→  const year = d.getUTCFullYear()
   348→  const month = String(d.getUTCMonth() + 1).padStart(2, '0')
   349→  const day = String(d.getUTCDate()).padStart(2, '0')
   350→  const hours = String(d.getUTCHours()).padStart(2, '0')
   351→  const minutes = String(d.getUTCMinutes()).padStart(2, '0')
   352→  const seconds = String(d.getUTCSeconds()).padStart(2, '0')
   353→  return `${year}-${month}-${day}T${hours}:${minutes}:${seconds}Z`
   354→}
